# STEP 1 of 2: Bootstrap — registers Syg.NpOnboardingChecklist in D365
# Import this FIRST as Unmanaged, then import SygnumPCFComponents_8.0.16.zip
# After the managed import succeeds you can delete the SygnumNpBootstrap solution.
$b64 = ""
$bytes = [Convert]::FromBase64String($b64)
$outPath = "$env:USERPROFILE\Desktop\SygnumNpBootstrap_unmanaged.zip"
[System.IO.File]::WriteAllBytes($outPath, $bytes)
Write-Host "Saved to: $outPath"
Write-Host "Import as UNMANAGED in make.powerapps.com, then import SygnumPCFComponents_8.0.16.zip"